      "entity": "contact",
      "name": "contact_table",
      "label": "All Contacts",
      "type": "table",
      "layout": ["first_name", "last_name", "email", "title", "account_id", "is_primary"]
    },
    {
      "entity": "contact",
      "name": "contact_form",
      "label": "Contact Details",
      "type": "form",
      "layout": ["first_name", "last_name", "email", "phone", "title", "account_id", "is_primary"]
    },
    {
      "entity": "deal",
      "name": "deal_pipeline",
      "label": "Sales Pipeline",
      "type": "kanban",
      "groupBy": "stage",
      "layout": ["name", "account_id", "amount", "close_date", "probability"]
    },
    {
      "entity": "deal",
      "name": "deal_form",
      "label": "Deal Details",
      "type": "form",
      "layout": ["name", "account_id", "amount", "stage", "close_date", "probability", "description"]
    },
    {
      "name": "pipeline_dashboard",
      "label": "Pipeline Dashboard",
      "type": "dashboard",
      "widgets": [
        {
          "type": "metric",
          "title": "Total Pipeline Value",
          "entity": "deal",
          "metric": "sum",
          "field": "amount",
          "filter": "stage != 'Closed-Lost'"
        },
        {
          "type": "chart",
          "title": "Pipeline Value by Stage",
          "entity": "deal",
          "chartType": "bar",
          "groupBy": "stage",
          "metric": "sum",
          "field": "amount"
        },
        {
          "type": "chart",
          "title": "Deal Count by Stage",
          "entity": "deal",
          "chartType": "pie",
          "groupBy": "stage",
          "metric": "count"
        },
        {
          "type": "metric",
          "title": "Total Accounts",
          "entity": "account",
          "metric": "count"
        }
      ]
    }
  ],
  "actions": [
    {
      "name": "advance_stage",
      "label": "Advance to Next Stage",
      "entity": "deal",
      "type": "transition",
      "transition": {
        "field": "stage",
        "to": "next"
      }
    },
    {
      "name": "mark_won",
      "label": "Mark as Won",
      "entity": "deal",
      "type": "transition",
      "transition": {
        "field": "stage",
        "to": "Closed-Won"
      }
    },
    {
      "name": "mark_lost",
      "label": "Mark as Lost",
      "entity": "deal",
      "type": "transition",
      "transition": {
        "field": "stage",
        "to": "Closed-Lost"
      }
    }
  ],
  "automations": [
    {
      "name": "notify_close_date",
      "label": "Notify on Close Date Approaching",
      "entity": "deal",
      "trigger": "field_change",
      "triggerConfig": {
        "field": "close_date",
        "condition": "within_7_days"
      },
      "actions": [
        {
          "type": "notification",
          "message": "Deal {{name}} closing soon"
        }
      ]
    },
    {
      "name": "update_probability",
      "label": "Auto-update Probability on Stage Change",
      "entity": "deal",
      "trigger": "field_change",
      "triggerConfig": {
        "field": "stage"
      },
      "actions": [
        {
          "type": "field_update",
          "field": "probability",
          "mapping": {
            "Prospecting": 10,
            "Qualification": 25,
            "Proposal": 60,
            "Closed-Won": 100,
            "Closed-Lost": 0
          }
        }
      ]
    }
  ],
  "navigation": [
    {
      "label": "Accounts",
      "icon": "building",
      "view": "account_table"
    },
    {
      "label": "Contacts",
      "icon": "users",
      "view": "contact_table"
    },
    {
      "label": "Pipeline",
      "icon": "chart-line",
      "view": "deal_pipeline"
    },
    {
      "label": "Dashboard",
      "icon": "dashboard",
      "view": "pipeline_dashboard"
    }
  ]
}
